local StructTowerInfo = LxClass("StructTowerInfo", nil)
function StructTowerInfo:StructTowerInfo()
    self.floor = 0                          --已经通关层数
    self.freeSweepNum = 0                   --当前免费次数
    self.buySweepNum = 0                    --已经购买次数
    self.phaseRewards = {}                  --领取过阶段奖励
    self.battleNum = 0                      --今日挑战层数
    self.towerType = 1                      --试炼类型
    self.maxChallengesNum = -1              --最大挑战次数，没限制-1
    self.historyMaxFloor = 0                --历史最大通关层数，不包含今天的
end

function StructTowerInfo:CreateByPb(pb)
    self.floor = pb.floor
    self.freeSweepNum = pb.freeSweepNum
    self.buySweepNum = pb.buySweepNum
    local list={}
    for i = 1, #pb.phaseReward do
        list[pb.phaseReward[i]]=pb.phaseReward[i]
    end
    self.phaseRewards = list
    if(pb.battleNum)then
        self.battleNum = pb.battleNum
    end
    if pb.towerType and pb.towerType > 0 then
        self.towerType = pb.towerType
    end
    self.maxChallengesNum = pb.maxChallengesNum
    self.historyMaxFloor =pb.historyMaxFloor
end

return StructTowerInfo